const body = $json.body;
const raw = body.transcript_text || '';
const words = raw.split(/\s+/);
// If >3000 words, take first+last 1500 words to stay in token budget
const text = words.length > 3000
  ? words.slice(0, 1500).join(' ') + '\n[...middle omitted...]\n' + words.slice(-1500).join(' ')
  : raw;
return { json: { rep_name: body.rep_name, rep_email: body.rep_email, deal_id: body.deal_id, call_date: body.call_date || new Date().toISOString(), duration_mins: body.duration_mins, transcript: text } };

const ai = JSON.parse($json.message.content);
const meta = $('Parse & Chunk').item.json;
const s = ai.scores;
const weighted_overall = Math.round((s.discovery*2 + s.pain*2 + s.value*1.5 + s.next_steps*2 + s.objection*1 + s.talk_ratio*1 + s.competitive*0.5) / 10);

const breakdown = Object.entries(s).map(([k,v]) => `${k.replace(/_/g,' ').toUpperCase()}: ${v}/5`).join('\n');

return { json: { ...meta, scores: s, overall: weighted_overall, call_summary: ai.call_summary, top_strength: ai.top_strength, top_improvement: ai.top_improvement, coaching_notes: ai.coaching_notes, score_breakdown: breakdown, scored_at: new Date().toISOString() } };

